diffs.replacement:
{
  "name": "PYTHENIANS LABO",
  "description": "High-velocity AI design forensic laboratory. Analyze digital artifacts, detect synthetic slop, and claim your place in the Pythian elite.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React, { useState, useMemo, useEffect } from 'react';
import { 
  Upload, Award, Zap, AlertCircle, RefreshCw, BarChart3, Fingerprint, 
  Image as ImageIcon, Coins, TrendingUp, Filter, X, ShieldCheck, 
  Activity, Download, ExternalLink, Microscope, ScanText, FileJson
} from 'lucide-react';
import { AnalysisResult, LeaderboardEntry } from './types';
import { analyzeImage } from './services/geminiService';

// --- Helpers ---

const getAvatarUrl = (username: string): string => {
  const seed = encodeURIComponent(username);
  return `https://api.dicebear.com/9.x/adventurer/svg?seed=${seed}&backgroundColor=0a0514&flip=true`;
};

const extractParticipant = (filename: string): string => {
  const nameWithoutExt = filename.replace(/\.[^/.]+$/, "");
  const parts = nameWithoutExt.split(/[-_ ]/);
  if (parts.length >= 2) {
    return parts.slice(0, 2).map(p => p.charAt(0).toUpperCase() + p.slice(1)).join(" ");
  }
  return parts[0].charAt(0).toUpperCase() + parts[0].slice(1);
};

// --- Components ---

const Modal: React.FC<{ isOpen: boolean; onClose: () => void; children: React.ReactNode }> = ({ isOpen, onClose, children }) => {
  if (!isOpen) return null;
  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/80 backdrop-blur-md" onClick={onClose}></div>
      <div className="relative bg-glass border border-purple-500/40 rounded-3xl w-full max-w-2xl max-h-[90vh] overflow-y-auto shadow-2xl p-8 animate-in fade-in zoom-in duration-300">
        <button onClick={onClose} className="absolute top-6 right-6 p-2 rounded-full hover:bg-purple-500/20 text-purple-400 transition-all">
          <X className="w-6 h-6" />
        </button>
        {children}
      </div>
    </div>
  );
};

const Header = () => (
  <header className="py-12 text-center relative">
    <div className="absolute top-0 left-1/2 -translate-x-1/2 w-64 h-64 bg-purple-600/10 blur-[120px] rounded-full pointer-events-none"></div>
    <h1 className="text-7xl font-black font-orbitron tracking-tightest text-transparent bg-clip-text bg-gradient-to-br from-white via-purple-300 to-indigo-500 mb-3 drop-shadow-[0_0_25px_rgba(168,85,247,0.3)]">
      PYTHENIANS LABO
    </h1>
    <div className="flex items-center justify-center gap-6">
      <div className="h-[2px] w-24 bg-gradient-to-r from-transparent via-purple-500/50 to-transparent"></div>
      <p className="text-purple-300/80 font-mono tracking-[0.4em] uppercase text-[10px] font-bold">
        SYNTHETIC ANOMALY DETECTION UNIT
      </p>
      <div className="h-[2px] w-24 bg-gradient-to-r from-transparent via-purple-500/50 to-transparent"></div>
    </div>
  </header>
);

const SlopMeter = ({ score }: { score: number }) => {
  const percentage = (score / 10) * 100;
  const getColor = () => {
    if (score >= 8) return 'from-emerald-500 to-teal-400 shadow-emerald-500/40';
    if (score >= 5) return 'from-amber-400 to-orange-500 shadow-orange-500/40';
    return 'from-rose-600 to-red-500 shadow-red-500/40';
  };

  return (
    <div className="w-full">
      <div className="flex justify-between items-end mb-2">
        <span className="text-[10px] font-black uppercase tracking-tighter text-purple-400 font-mono">INTENT INDEX</span>
        <span className="text-2xl font-orbitron font-black text-white leading-none">{score}<span className="text-[10px] opacity-40 ml-1">/10</span></span>
      </div>
      <div className="h-3 w-full bg-black/40 rounded-full p-0.5 border border-white/5 overflow-hidden">
        <div 
          className={`h-full transition-all duration-1000 ease-out rounded-full bg-gradient-to-r ${getColor()} shadow-[0_0_15px_rgba(0,0,0,0.5)]`}
          style={{ width: `${percentage}%` }}
        />
      </div>
    </div>
  );
};

const AnalysisCard: React.FC<{ result: AnalysisResult; onDelete: (id: string) => void }> = ({ result, onDelete }) => {
  const [showDetails, setShowDetails] = useState(false);
  const participant = extractParticipant(result.name);
  const avatarUrl = getAvatarUrl(participant);

  const downloadReport = () => {
    const report = {
      ...result,
      lab: "PYTHENIANS LABO",
      verifiedAt: new Date(result.timestamp).toISOString()
    };
    const blob = new Blob([JSON.stringify(report, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `forensic-report-${result.id.slice(0, 8)}.json`;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <>
      <div className="bg-glass rounded-[2rem] overflow-hidden group hover:neon-border transition-all duration-500 flex flex-col border border-purple-500/10 h-full relative">
        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-purple-500/40 to-transparent animate-scan z-20"></div>

        <div className="relative h-64 overflow-hidden bg-black/40">
          <img src={result.imageUrl} alt={result.name} className="w-full h-full object-cover transition-transform duration-1000 group-hover:scale-110" />
          <div className="absolute inset-0 bg-gradient-to-t from-black/90 via-black/20 to-transparent"></div>

          <div className="absolute top-4 left-4 flex gap-2 z-10">
             <div className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest backdrop-blur-2xl border ${result.isAiGenerated ? 'bg-red-500/10 border-red-500/30 text-red-400' : 'bg-emerald-500/10 border-emerald-500/30 text-emerald-400'}`}>
                {result.isAiGenerated ? 'SYNTHETIC SLOP' : 'AUTHENTIC CRAFT'}
             </div>
          </div>

          <button 
            onClick={() => onDelete(result.id)}
            className="absolute top-4 right-4 p-2 rounded-xl bg-black/60 hover:bg-red-500/80 transition-all border border-white/10 z-10"
          >
            <X className="w-4 h-4 text-white" />
          </button>

          <div className="absolute bottom-4 left-4 right-4 flex justify-between items-end">
            <div className="flex flex-col gap-1">
              <h3 className="text-lg font-black font-orbitron text-white leading-tight drop-shadow-lg truncate max-w-[180px]">{result.name}</h3>
              <div className="flex items-center gap-2 text-[9px] font-bold text-purple-400 font-mono uppercase">
                <Microscope className="w-3 h-3" /> UID: {result.id.slice(0, 8)}
              </div>
            </div>
            <div className="flex items-center gap-2 bg-black/60 backdrop-blur-xl px-3 py-1.5 rounded-2xl border border-white/10">
              <img src={avatarUrl} alt={participant} className="w-5 h-5 rounded-full bg-purple-900 border border-purple-500/40" />
              <span className="text-[10px] font-black text-white/90">{participant}</span>
            </div>
          </div>
        </div>

        <div className="p-7 space-y-6 flex-1 flex flex-col">
          <SlopMeter score={result.score} />

          <div className="flex-1 space-y-4">
            <div className="relative p-4 bg-purple-500/5 rounded-2xl border border-purple-500/10 border-l-4 border-l-purple-500/40">
              <ScanText className="absolute top-4 right-4 w-4 h-4 text-purple-500/30" />
              <p className="text-xs text-purple-100/70 leading-relaxed font-medium italic">
                "{result.reasoning}"
              </p>
            </div>

            <div className="flex flex-wrap gap-2">
              {result.technicalDetails.map((detail, i) => (
                <span key={i} className="text-[8px] bg-purple-900/30 border border-purple-500/20 px-2 py-1 rounded text-purple-300 uppercase font-bold tracking-widest">
                  {detail}
                </span>
              ))}
            </div>
          </div>

          <div className="pt-6 border-t border-purple-500/10 flex gap-3">
            <button 
              onClick={() => setShowDetails(true)}
              className="flex-1 bg-purple-600 hover:bg-purple-500 text-white py-3 rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] transition-all flex items-center justify-center gap-2 shadow-lg shadow-purple-600/20"
            >
              <ExternalLink className="w-4 h-4" /> Preview Report
            </button>
            <button 
              onClick={downloadReport}
              className="p-3 bg-white/5 hover:bg-white/10 text-white rounded-2xl border border-white/10 transition-all"
              title="Download JSON Report"
            >
              <FileJson className="w-5 h-5" />
            </button>
          </div>
        </div>
      </div>

      <Modal isOpen={showDetails} onClose={() => setShowDetails(false)}>
        <div className="space-y-8">
          <div className="flex items-center gap-4 border-b border-purple-500/20 pb-6">
            <div className="p-4 bg-purple-600/20 rounded-3xl border border-purple-500/40">
              <ShieldCheck className="w-8 h-8 text-purple-400" />
            </div>
            <div>
              <h2 className="text-2xl font-black font-orbitron text-white">FORENSIC DOSSIER</h2>
              <p className="text-[10px] font-mono text-purple-400 uppercase tracking-widest">Laboratory Case No: {result.id}</p>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
             <div className="aspect-square rounded-3xl overflow-hidden border border-white/10 shadow-2xl">
               <img src={result.imageUrl} alt="Artifact Preview" className="w-full h-full object-cover" />
             </div>
             <div className="space-y-6">
                <div>
                  <label className="text-[10px] font-black text-purple-500 uppercase block mb-2">Subject Identity</label>
                  <div className="flex items-center gap-3 p-3 bg-white/5 rounded-2xl border border-white/5">
                    <img src={avatarUrl} alt={participant} className="w-10 h-10 rounded-full bg-purple-900" />
                    <span className="font-bold text-white">{participant}</span>
                  </div>
                </div>
                <div>
                  <label className="text-[10px] font-black text-purple-500 uppercase block mb-2">Technical Verdict</label>
                  <div className={`p-4 rounded-2xl font-orbitron font-bold text-center border ${result.isAiGenerated ? 'bg-red-500/20 border-red-500/40 text-red-400' : 'bg-emerald-500/20 border-emerald-500/40 text-emerald-400'}`}>
                    {result.isAiGenerated ? 'SYNTHETIC SLOP DETECTED' : 'HUMAN CRAFT VERIFIED'}
                  </div>
                </div>
                <div>
                   <label className="text-[10px] font-black text-purple-500 uppercase block mb-2">Lab Confidence</label>
                   <div className="text-3xl font-black text-white font-orbitron">{result.confidence}%</div>
                </div>
             </div>
          </div>

          <div className="space-y-4">
            <h3 className="text-sm font-black text-purple-200 uppercase flex items-center gap-2">
              <Zap className="w-4 h-4 text-purple-400" /> Analyst Commentary
            </h3>
            <div className="bg-purple-900/20 p-6 rounded-3xl border border-purple-500/10 text-sm leading-relaxed text-purple-100/90 font-medium font-mono">
              [LOG]: {result.reasoning}
            </div>
          </div>

          <div className="flex justify-end gap-4 pt-6 border-t border-purple-500/10">
             <button onClick={downloadReport} className="flex items-center gap-2 text-[10px] font-black text-purple-400 uppercase hover:text-white transition-colors">
               <Download className="w-4 h-4" /> Save Certificate
             </button>
          </div>
        </div>
      </Modal>
    </>
  );
};

const Podium = ({ winners, pool }: { winners: LeaderboardEntry[], pool: number }) => {
  if (winners.length === 0) return null;
  const tiers = [
    { label: 'TITAN', color: 'from-slate-400 to-slate-200 shadow-slate-400/30', share: 0.3, rank: 2 },
    { label: 'APEX', color: 'from-yellow-500 to-amber-200 shadow-yellow-500/40', share: 0.5, rank: 1 },
    { label: 'ELITE', color: 'from-amber-800 to-orange-400 shadow-amber-800/30', share: 0.2, rank: 3 },
  ];

  return (
    <div className="relative py-16">
      <div className="absolute inset-0 bg-purple-600/5 blur-3xl rounded-full"></div>
      <div className="flex items-end justify-center gap-4 md:gap-12 h-96 relative z-10">
        {[1, 0, 2].map((idx) => {
          const winner = winners[idx];
          const tier = tiers[idx];
          if (!winner) return null;
          return (
            <div key={winner.id} className={`flex flex-col items-center group ${idx === 0 ? 'scale-110 -translate-y-8' : 'opacity-80'}`}>
              <div className="relative mb-6">
                <div className={`absolute -inset-4 bg-gradient-to-br ${tier.color} blur-2xl opacity-20 group-hover:opacity-40 animate-pulse-soft rounded-full`}></div>
                <img src={winner.avatar} alt={winner.username} className="w-24 h-24 md:w-32 md:h-32 rounded-full border-4 border-white/20 bg-black/40 relative z-10 transition-transform group-hover:scale-110" />
                <div className={`absolute -bottom-2 -right-2 bg-gradient-to-br ${tier.color} text-black p-2 rounded-xl z-20 font-black font-orbitron text-xs shadow-xl`}>
                  #{tier.rank}
                </div>
              </div>
              <div className="bg-glass rounded-t-3xl w-40 md:w-56 h-32 md:h-48 flex flex-col items-center p-6 border-t-2 border-purple-500/20 shadow-2xl">
                 <span className="text-white font-black text-sm md:text-lg mb-1 truncate w-full text-center">{winner.username}</span>
                 <span className="text-[10px] font-orbitron font-black text-purple-400 uppercase tracking-widest mb-3">{tier.label}</span>
                 <div className="flex items-center gap-2 bg-white/5 px-4 py-2 rounded-full border border-white/5">
                   <Coins className="w-3.5 h-3.5 text-yellow-500" />
                   <span className="text-xs font-orbitron font-bold text-white">+{Math.floor(pool * tier.share).toLocaleString()}</span>
                 </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

// --- Main App ---

export default function App() {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [results, setResults] = useState<AnalysisResult[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [prizePool, setPrizePool] = useState<number>(25000);
  const [activeFilter, setActiveFilter] = useState<string | null>(null);

  const allTechnicalDetails = useMemo(() => {
    const details = new Set<string>();
    results.forEach(res => res.technicalDetails.forEach(d => details.add(d)));
    return Array.from(details).sort();
  }, [results]);

  const filteredResults = useMemo(() => {
    if (!activeFilter) return results;
    return results.filter(res => res.technicalDetails.includes(activeFilter));
  }, [results, activeFilter]);

  const leaderboard = useMemo(() => {
    const userScores: Record<string, { total: number; count: number; best: number }> = {};
    results.forEach(res => {
      const username = extractParticipant(res.name);
      if (!userScores[username]) userScores[username] = { total: 0, count: 0, best: 0 };
      userScores[username].total += res.score;
      userScores[username].count += 1;
      userScores[username].best = Math.max(userScores[username].best, res.score);
    });
    return Object.entries(userScores)
      .map(([username, stats]) => ({
        id: username,
        username,
        points: Math.floor(stats.best * 2000 + (stats.total / stats.count) * 1000),
        avatar: getAvatarUrl(username)
      }))
      .sort((a, b) => b.points - a.points)
      .slice(0, 10);
  }, [results]);

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const files = event.target.files;
    if (!files || files.length === 0) return;

    setIsAnalyzing(true);
    setError(null);

    try {
      const fileArray = Array.from(files);

      // CONCURRENT PROCESSING FOR HIGH VELOCITY
      const analysisPromises = fileArray.map(async (file) => {
        const reader = new FileReader();
        const base64Data = await new Promise<string>((resolve) => {
          reader.onload = (e) => resolve(e.target?.result as string);
          reader.readAsDataURL(file);
        });

        const analysis = await analyzeImage(base64Data, file.type);

        return {
          id: Math.random().toString(36).substr(2, 9),
          imageUrl: base64Data,
          name: file.name,
          score: analysis.score,
          isAiGenerated: analysis.isAiGenerated,
          confidence: analysis.confidence,
          reasoning: analysis.reasoning,
          technicalDetails: analysis.technicalDetails,
          timestamp: Date.now(),
        } as AnalysisResult;
      });

      const newResults = await Promise.all(analysisPromises);
      setResults(prev => [...newResults, ...prev]);
    } catch (err) {
      console.error(err);
      setError("Forensic sequence interrupted. Verify connection and retry.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <div className="min-h-screen px-4 py-8 md:px-12 max-w-[1600px] mx-auto">
      <Header />

      <main className="space-y-12">
        {/* Top Control Bar */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 items-start">
           <div className="bg-glass p-8 rounded-[2.5rem] border border-purple-500/20 relative group overflow-hidden">
             <div className="absolute -bottom-8 -right-8 opacity-10 group-hover:opacity-20 transition-opacity">
                <Coins className="w-40 h-40 text-yellow-500 -rotate-12" />
             </div>
             <div className="relative z-10">
               <div className="flex items-center gap-3 mb-6">
                 <TrendingUp className="text-purple-400 w-5 h-5" />
                 <h3 className="text-xs font-black font-orbitron uppercase tracking-widest text-purple-200">PRIZE ALLOCATION</h3>
               </div>
               <div className="space-y-6">
                 <div className="relative">
                   <input 
                      type="number" 
                      value={prizePool}
                      onChange={(e) => setPrizePool(Number(e.target.value))}
                      className="w-full bg-black/40 border border-white/5 rounded-2xl py-5 px-8 text-3xl font-orbitron text-white focus:outline-none focus:border-purple-500 transition-all shadow-inner"
                    />
                    <span className="absolute right-6 top-1/2 -translate-y-1/2 text-[10px] font-black text-purple-500 font-mono tracking-widest">PYTH</span>
                 </div>
                 <div className="grid grid-cols-3 gap-4">
                    {[{l: 'APEX', p: 0.5}, {l: 'TITAN', p: 0.3}, {l: 'ELITE', p: 0.2}].map(t => (
                      <div key={t.l} className="text-center p-3 bg-white/5 rounded-2xl border border-white/5">
                        <div className="text-[8px] font-black text-purple-400 mb-1">{t.l}</div>
                        <div className="text-xs font-orbitron text-white">{Math.floor(prizePool * t.p).toLocaleString()}</div>
                      </div>
                    ))}
                 </div>
               </div>
             </div>
           </div>

           <div className="lg:col-span-2">
              {leaderboard.length > 0 ? (
                <Podium winners={leaderboard} pool={prizePool} />
              ) : (
                <div className="bg-glass rounded-[2.5rem] p-24 flex flex-col items-center justify-center text-center border-2 border-dashed border-purple-900/20 h-full min-h-[400px]">
                  <Award className="w-16 h-16 text-purple-900/40 mb-6" />
                  <h3 className="text-xl font-orbitron text-purple-500 mb-2 uppercase tracking-widest">Winners Circle Empty</h3>
                  <p className="text-purple-700/60 text-[10px] font-black uppercase tracking-widest">Awaiting forensic upload from active participants</p>
                </div>
              )}
           </div>
        </div>

        {/* Upload & Dashboard Section */}
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">

          <div className="lg:col-span-4 space-y-8">
            <div className="sticky top-12 space-y-8">
              <div className="relative group">
                <div className="absolute -inset-0.5 bg-gradient-to-br from-purple-500 to-fuchsia-600 rounded-[2.5rem] blur opacity-10 group-hover:opacity-30 transition duration-1000"></div>
                <div className="relative bg-glass rounded-[2.5rem] p-12 flex flex-col items-center justify-center border-2 border-dashed border-purple-500/30 hover:border-purple-500/60 transition-all cursor-pointer overflow-hidden">
                  <input 
                    type="file" multiple accept="image/*" onChange={handleFileUpload}
                    className="absolute inset-0 opacity-0 cursor-pointer z-30"
                    disabled={isAnalyzing}
                  />
                  <div className="bg-purple-600/10 p-8 rounded-[2rem] mb-6 group-hover:scale-110 transition-transform duration-500 relative z-20">
                    {isAnalyzing ? (
                      <RefreshCw className="w-16 h-16 text-purple-400 animate-spin" />
                    ) : (
                      <Upload className="w-16 h-16 text-purple-400" />
                    )}
                  </div>
                  <h2 className="text-2xl font-black font-orbitron mb-2 text-white relative z-20">DEPLOY SCANS</h2>
                  <p className="text-purple-400/60 text-center uppercase tracking-[0.2em] text-[10px] font-black relative z-20">
                    Concurrent Neural Analysis Protocol
                  </p>

                  {isAnalyzing && (
                    <div className="mt-8 flex items-center gap-3 py-3 px-6 bg-purple-500/10 rounded-full animate-pulse border border-purple-500/20 z-20">
                      <Activity className="w-4 h-4 text-fuchsia-400" />
                      <span className="text-[10px] font-black text-fuchsia-400 uppercase tracking-widest">Processing Data Streams...</span>
                    </div>
                  )}

                  {error && (
                    <div className="mt-6 flex items-center gap-3 text-rose-400 bg-rose-400/10 px-6 py-3 rounded-2xl border border-rose-400/20 z-20">
                      <AlertCircle className="w-5 h-5" />
                      <span className="text-[10px] font-black uppercase tracking-tight">{error}</span>
                    </div>
                  )}
                </div>
              </div>

              {leaderboard.length > 3 && (
                <div className="bg-glass rounded-[2.5rem] p-8 border border-purple-500/20">
                  <h3 className="text-xs font-black font-orbitron uppercase text-purple-400 mb-6 flex items-center gap-2 tracking-widest">
                    <BarChart3 className="w-4 h-4" /> Lab Standings
                  </h3>
                  <div className="space-y-4">
                    {leaderboard.slice(3).map((entry, i) => (
                      <div key={entry.id} className="flex items-center justify-between p-3 rounded-2xl bg-white/5 border border-white/5 group hover:border-purple-500/40 transition-all">
                        <div className="flex items-center gap-4">
                          <span className="text-[10px] font-mono text-purple-600 w-4 font-black">{i + 4}</span>
                          <img src={entry.avatar} alt={entry.username} className="w-10 h-10 rounded-full border border-white/10" />
                          <span className="text-xs font-bold text-white/90 truncate max-w-[120px]">{entry.username}</span>
                        </div>
                        <span className="text-[10px] font-orbitron font-bold text-purple-400 bg-purple-400/10 px-3 py-1 rounded-full">{entry.points.toLocaleString()}</span>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>

          <div className="lg:col-span-8 space-y-8">
            <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 px-4">
              <div className="flex items-center gap-4">
                <div className="p-3 bg-purple-600/20 rounded-2xl">
                  <Fingerprint className="text-purple-400 w-8 h-8" />
                </div>
                <div>
                  <h2 className="text-4xl font-black font-orbitron text-white tracking-tightest">LAB FEED</h2>
                  <p className="text-[10px] font-black uppercase tracking-[0.4em] text-purple-500">{results.length} Artifacts in database</p>
                </div>
              </div>

              {results.length > 0 && (
                <div className="flex flex-wrap gap-2 justify-end">
                   <button
                    onClick={() => setActiveFilter(null)}
