export default function App() {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [results, setResults] = useState<AnalysisResult[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [prizePool, setPrizePool] = useState<number>(25000);
  const [activeFilter, setActiveFilter] = useState<string | null>(null);

  const deleteResult = (id: string) => {
    setResults(prev => prev.filter(r => r.id !== id));
  };

  const allTechnicalDetails = useMemo(() => {
    const details = new Set<string>();
    results.forEach(res => res.technicalDetails.forEach(d => details.add(d)));
    return Array.from(details).sort();
  }, [results]);

  const filteredResults = useMemo(() => {
    if (!activeFilter) return results;
    return results.filter(res => res.technicalDetails.includes(activeFilter));
  }, [results, activeFilter]);

  const leaderboard = useMemo(() => {
    const userScores: Record<string, { total: number; count: number; best: number }> = {};
    results.forEach(res => {
      const username = extractParticipant(res.name);
      if (!userScores[username]) userScores[username] = { total: 0, count: 0, best: 0 };
      userScores[username].total += res.score;
      userScores[username].count += 1;
      userScores[username].best = Math.max(userScores[username].best, res.score);
    });
    return Object.entries(userScores)
      .map(([username, stats]) => ({
        id: username,
        username,
        points: Math.floor(stats.best * 2000 + (stats.total / stats.count) * 1000),
        avatar: getAvatarUrl(username)
      }))
      .sort((a, b) => b.points - a.points)
      .slice(0, 10);
  }, [results]);

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const files = event.target.files;
    if (!files || files.length === 0) return;

    setIsAnalyzing(true);
    setError(null);

    try {
      const fileArray = Array.from(files) as File[];

      const analysisPromises = fileArray.map(async (file) => {
        const reader = new FileReader();
        const base64Data = await new Promise<string>((resolve) => {
          reader.onload = (e) => resolve(e.target?.result as string);
          reader.readAsDataURL(file);
        });

        const analysis = await analyzeImage(base64Data, file.type);

        return {
          id: Math.random().toString(36).substr(2, 9),
          imageUrl: base64Data,
          name: file.name,
          score: analysis.score,
          isAiGenerated: analysis.isAiGenerated,
          confidence: analysis.confidence,
          reasoning: analysis.reasoning,
          technicalDetails: analysis.technicalDetails,
          timestamp: Date.now(),
        } as AnalysisResult;
      });

      const newResults = await Promise.all(analysisPromises);
      setResults(prev => [...newResults, ...prev]);
    } catch (err) {
      console.error(err);
      setError("Forensic sequence interrupted. Verify connection and retry.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <div className="min-h-screen px-4 py-8 md:px-12 max-w-[1600px] mx-auto">
      <Header />

      <main className="space-y-12">
        {/* Top Control Bar */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 items-start">
           <div className="bg-glass p-8 rounded-[2.5rem] border border-purple-500/20 relative group overflow-hidden">
             <div className="absolute -bottom-8 -right-8 opacity-10 group-hover:opacity-20 transition-opacity">
                <Coins className="w-40 h-40 text-yellow-500 -rotate-12" />
             </div>
             <div className="relative z-10">
               <div className="flex items-center gap-3 mb-6">
                 <TrendingUp className="text-purple-400 w-5 h-5" />
                 <h3 className="text-xs font-black font-orbitron uppercase tracking-widest text-purple-200">PRIZE ALLOCATION</h3>
               </div>
               <div className="space-y-6">
                 <div className="relative">
                   <input 
                      type="number" 
                      value={prizePool}
                      onChange={(e) => setPrizePool(Number(e.target.value))}
                      className="w-full bg-black/40 border border-white/5 rounded-2xl py-5 px-8 text-3xl font-orbitron text-white focus:outline-none focus:border-purple-500 transition-all shadow-inner"
                    />
                    <span className="absolute right-6 top-1/2 -translate-y-1/2 text-[10px] font-black text-purple-500 font-mono tracking-widest">PYTH</span>
                 </div>
                 <div className="grid grid-cols-3 gap-4">
                    {[{l: 'APEX', p: 0.5}, {l: 'TITAN', p: 0.3}, {l: 'ELITE', p: 0.2}].map(t => (
                      <div key={t.l} className="text-center p-3 bg-white/5 rounded-2xl border border-white/5">
                        <div className="text-[8px] font-black text-purple-400 mb-1">{t.l}</div>
                        <div className="text-xs font-orbitron text-white">{Math.floor(prizePool * t.p).toLocaleString()}</div>
                      </div>
                    ))}
                 </div>
               </div>
             </div>
           </div>

           <div className="lg:col-span-2">
              {leaderboard.length > 0 ? (
                <Podium winners={leaderboard} pool={prizePool} />
              ) : (
                <div className="bg-glass rounded-[2.5rem] p-24 flex flex-col items-center justify-center text-center border-2 border-dashed border-purple-900/20 h-full min-h-[400px]">
                  <Award className="w-16 h-16 text-purple-900/40 mb-6" />
                  <h3 className="text-xl font-orbitron text-purple-500 mb-2 uppercase tracking-widest">Winners Circle Empty</h3>
                  <p className="text-purple-700/60 text-[10px] font-black uppercase tracking-widest">Awaiting forensic upload from active participants</p>
                </div>
              )}
           </div>
        </div>

        {/* Upload & Dashboard Section */}
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">

          <div className="lg:col-span-4 space-y-8">
            <div className="sticky top-12 space-y-8">
              <div className="relative group">
                <div className="absolute -inset-0.5 bg-gradient-to-br from-purple-500 to-fuchsia-600 rounded-[2.5rem] blur opacity-10 group-hover:opacity-30 transition duration-1000"></div>
                <div className="relative bg-glass rounded-[2.5rem] p-12 flex flex-col items-center justify-center border-2 border-dashed border-purple-500/30 hover:border-purple-500/60 transition-all cursor-pointer overflow-hidden">
                  <input 
                    type="file" multiple accept="image/*" onChange={handleFileUpload}
                    className="absolute inset-0 opacity-0 cursor-pointer z-30"
                    disabled={isAnalyzing}
                  />
                  <div className="bg-purple-600/10 p-8 rounded-[2rem] mb-6 group-hover:scale-110 transition-transform duration-500 relative z-20">
                    {isAnalyzing ? (
                      <RefreshCw className="w-16 h-16 text-purple-400 animate-spin" />
                    ) : (
                      <Upload className="w-16 h-16 text-purple-400" />
                    )}
                  </div>
                  <h2 className="text-2xl font-black font-orbitron mb-2 text-white relative z-20">DEPLOY SCANS</h2>
                  <p className="text-purple-400/60 text-center uppercase tracking-[0.2em] text-[10px] font-black relative z-20">
                    Concurrent Neural Analysis Protocol
                  </p>

