const getAvatarUrl = (username: string): string => {
  const seed = encodeURIComponent(username);
  return `https://api.dicebear.com/9.x/adventurer/svg?seed=${seed}&backgroundColor=0a0514&flip=true`;
};

const extractParticipant = (filename: string): string => {
  const nameWithoutExt = filename.replace(/\.[^/.]+$/, "");
  const parts = nameWithoutExt.split(/[-_ ]/);
  if (parts.length >= 2) {
    return parts.slice(0, 2).map(p => p.charAt(0).toUpperCase() + p.slice(1)).join(" ");
  }
  return parts[0].charAt(0).toUpperCase() + parts[0].slice(1);
};

