};

// --- Main App ---

export default function App() {
  const [results, setResults] = useState<AnalysisResult[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [prizePool, setPrizePool] = useState<number>(25000);
  const [activeFilter, setActiveFilter] = useState<string | null>(null);

  const deleteResult = (id: string) => {
    setResults(prev => prev.filter(r => r.id !== id));
  };

  const allTechnicalDetails = useMemo(() => {
    const details = new Set<string>();
    results.forEach(res => {
      if (res.status === 'success') {
        res.technicalDetails.forEach(d => details.add(d));
      }
    });
    return Array.from(details).sort();
  }, [results]);

  const filteredResults = useMemo(() => {
    if (!activeFilter) return results;
    return results.filter(res => res.status === 'success' && res.technicalDetails.includes(activeFilter));
  }, [results, activeFilter]);

  const leaderboard = useMemo(() => {
    const userScores: Record<string, { total: number; count: number; best: number }> = {};
    results.filter(r => r.status === 'success').forEach(res => {
      const username = extractParticipant(res.name);
      if (!userScores[username]) userScores[username] = { total: 0, count: 0, best: 0 };
      userScores[username].total += res.score;
      userScores[username].count += 1;
      userScores[username].best = Math.max(userScores[username].best, res.score);
    });
    return Object.entries(userScores)
      .map(([username, stats]) => ({
        id: username,
        username,
        points: Math.floor(stats.best * 2000 + (stats.total / stats.count) * 1000),
        avatar: getAvatarUrl(username)
      }))
      .sort((a, b) => b.points - a.points)
      .slice(0, 10);
  }, [results]);

  const isAnyAnalyzing = results.some(r => r.status === 'pending');

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const files = event.target.files;
    if (!files || files.length === 0) return;

    setError(null);
    const fileArray = Array.from(files) as File[];

    const pendingResults: AnalysisResult[] = fileArray.map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      imageUrl: URL.createObjectURL(file),
      name: file.name,
      score: 0,
      isAiGenerated: false,
      confidence: 0,
      reasoning: "Forensic stream initiating...",
      technicalDetails: [],
      timestamp: Date.now(),
      status: 'pending'
    }));

    setResults(prev => [...pendingResults, ...prev]);

    pendingResults.forEach(async (pending, index) => {
      const file = fileArray[index];
      try {
        const optimizedBase64 = await fastResize(file, 1024);
        const analysis = await analyzeImage(optimizedBase64, 'image/jpeg');

        setResults(prev => prev.map(item => 
          item.id === pending.id 
            ? { ...item, ...analysis, imageUrl: optimizedBase64, status: 'success' } 
            : item
        ));
      } catch (err) {
        console.error(err);
        setResults(prev => prev.map(item => 
          item.id === pending.id 
            ? { ...item, status: 'error', reasoning: "Scan failed. Link unstable." } 
            : item
        ));
      }
    });
  };

  return (
    <div className="min-h-screen px-6 py-8 md:px-16 max-w-[1700px] mx-auto">
      <Header />

      <main className="space-y-20">
        {/* Top Control Bar */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-12 items-start">
           <div className="bg-glass p-10 rounded-[3rem] border border-purple-500/20 relative group overflow-hidden shadow-2xl">
             <div className="absolute -bottom-12 -right-12 opacity-5 group-hover:opacity-10 transition-opacity">
                <Coins className="w-56 h-56 text-yellow-500 -rotate-12" />
             </div>
             <div className="relative z-10">
               <div className="flex items-center gap-4 mb-8">
                 <div className="p-3 bg-purple-600/20 rounded-2xl">
                    <TrendingUp className="text-purple-400 w-6 h-6" />
                 </div>
                 <h3 className="text-xs font-black font-orbitron uppercase tracking-[0.3em] text-purple-200">PRIZE ALLOCATION</h3>
               </div>
               <div className="space-y-8">
                 <div className="relative">
                   <input 
                      type="number" 
                      value={prizePool}
                      onChange={(e) => setPrizePool(Number(e.target.value))}
                      className="w-full bg-black/50 border border-white/10 rounded-[2rem] py-6 px-10 text-4xl font-orbitron text-white focus:outline-none focus:border-purple-500 transition-all shadow-inner"
                    />
                    <div className="absolute right-8 top-1/2 -translate-y-1/2 flex flex-col items-end">
                       <span className="text-[10px] font-black text-purple-500 font-mono tracking-widest">UNIT</span>
                       <span className="text-[12px] font-orbitron font-black text-white">PYTH</span>
                    </div>
                 </div>
                 <div className="grid grid-cols-3 gap-4">
                    {[{l: 'APEX', p: 0.5, c: 'text-yellow-500'}, {l: 'TITAN', p: 0.3, c: 'text-slate-300'}, {l: 'ELITE', p: 0.2, c: 'text-amber-700'}].map(t => (
                      <div key={t.l} className="text-center p-4 bg-white/[0.03] rounded-3xl border border-white/5 hover:border-white/20 transition-colors">
                        <div className={`text-[9px] font-black mb-1 uppercase tracking-widest ${t.c}`}>{t.l}</div>
                        <div className="text-sm font-orbitron text-white font-bold">{Math.floor(prizePool * t.p).toLocaleString()}</div>
                      </div>
                    ))}
                 </div>
               </div>
             </div>
           </div>

           <div className="lg:col-span-2">
              {leaderboard.length > 0 ? (
                <Podium winners={leaderboard} pool={prizePool} />
              ) : (
                <div className="bg-glass rounded-[3rem] p-24 flex flex-col items-center justify-center text-center border-2 border-dashed border-purple-900/20 h-full min-h-[450px]">
                  <Award className="w-20 h-20 text-purple-900/20 mb-8" />
                  <h3 className="text-2xl font-orbitron text-purple-600/40 mb-3 uppercase tracking-widest">Winners Circle Awaiting Data</h3>
