            <div className="sticky top-12 space-y-12">
              <div className="relative group">
                <div className="absolute -inset-1 bg-gradient-to-br from-purple-500 to-fuchsia-600 rounded-[3rem] blur-2xl opacity-10 group-hover:opacity-30 transition duration-1000"></div>
                <div className="relative bg-glass rounded-[3rem] p-16 flex flex-col items-center justify-center border-2 border-dashed border-purple-500/20 hover:border-purple-500/50 transition-all cursor-pointer overflow-hidden shadow-2xl">
                  <input 
                    type="file" multiple accept="image/*" onChange={handleFileUpload}
                    className="absolute inset-0 opacity-0 cursor-pointer z-30"
                  />
                  <div className="bg-purple-600/10 p-10 rounded-[2.5rem] mb-8 group-hover:scale-110 transition-transform duration-700 relative z-20 shadow-inner">
                    {isAnyAnalyzing ? (
                      <Wind className="w-20 h-20 text-purple-400 animate-pulse" />
                    ) : (
                      <Upload className="w-20 h-20 text-purple-400" />
                    )}
                  </div>
                  <h2 className="text-3xl font-black font-orbitron mb-3 text-white relative z-20 uppercase tracking-tighter">Velocity Scan</h2>
                  <p className="text-purple-400/60 text-center uppercase tracking-[0.4em] text-[11px] font-black relative z-20 leading-relaxed max-w-[200px]">
                    MULTI-CHANNEL FORENSIC ARCHIVE
                  </p>

                  {isAnyAnalyzing && (
                    <div className="mt-10 flex items-center gap-4 py-4 px-8 bg-purple-500/10 rounded-full animate-pulse border border-purple-500/30 z-20 shadow-xl">
                      <Activity className="w-5 h-5 text-fuchsia-400" />
                      <span className="text-[11px] font-black text-fuchsia-400 uppercase tracking-widest font-orbitron">Neural Burst Active</span>
                    </div>
                  )}

                  {error && (
                    <div className="mt-8 flex items-center gap-4 text-rose-400 bg-rose-400/10 px-8 py-4 rounded-2xl border border-rose-400/30 z-20 shadow-xl">
                      <AlertCircle className="w-6 h-6" />
                      <span className="text-[11px] font-black uppercase tracking-widest">{error}</span>
                    </div>
                  )}
                </div>
              </div>

              {leaderboard.length > 3 && (
                <div className="bg-glass rounded-[3rem] p-10 border border-purple-500/10 shadow-2xl">
                  <h3 className="text-[11px] font-black font-orbitron uppercase text-purple-400 mb-8 flex items-center gap-3 tracking-[0.3em]">
                    <BarChart3 className="w-5 h-5" /> Laboratory Standings
                  </h3>
                  <div className="space-y-5">
                    {leaderboard.slice(3).map((entry, i) => (
                      <div key={entry.id} className="flex items-center justify-between p-4 rounded-2xl bg-white/[0.02] border border-white/5 group hover:border-purple-500/40 transition-all shadow-sm">
                        <div className="flex items-center gap-5">
                          <span className="text-[11px] font-mono text-purple-600/50 w-5 font-black">#{i + 4}</span>
                          <img src={entry.avatar} alt={entry.username} className="w-12 h-12 rounded-full border border-white/10 shadow-lg" />
                          <span className="text-sm font-black text-white/90 truncate max-w-[130px] tracking-tight">{entry.username}</span>
                        </div>
                        <div className="flex flex-col items-end">
                           <span className="text-[11px] font-orbitron font-black text-purple-400">{entry.points.toLocaleString()}</span>
                           <span className="text-[8px] font-mono text-purple-700 uppercase">POINTS</span>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>

          <div className="lg:col-span-8 space-y-12">
            <div className="flex flex-col md:flex-row md:items-end justify-between gap-8 px-6">
              <div className="flex items-center gap-6">
                <div className="p-4 bg-purple-600/20 rounded-3xl shadow-inner">
                  <Fingerprint className="text-purple-400 w-10 h-10" />
                </div>
                <div>
                  <h2 className="text-5xl font-black font-orbitron text-white tracking-tighter">DATA FEED</h2>
