const SlopMeter = ({ score }: { score: number }) => {
  const segments = Array.from({ length: 10 });
  const getColor = (i: number) => {
    if (i >= score) return 'bg-white/5';
    if (score >= 8) return 'bg-emerald-500 shadow-[0_0_10px_rgba(16,185,129,0.5)]';
    if (score >= 5) return 'bg-amber-500 shadow-[0_0_10px_rgba(245,158,11,0.5)]';
    return 'bg-rose-500 shadow-[0_0_10px_rgba(244,63,94,0.5)]';
  };

  return (
    <div className="w-full">
      <div className="flex justify-between items-end mb-3">
        <span className="text-[9px] font-black uppercase tracking-widest text-purple-500/80 font-mono">NEURAL FIDELITY</span>
        <span className="text-3xl font-black text-white leading-none">{score}<span className="text-[12px] opacity-30 ml-1 font-mono">/10</span></span>
      </div>
      <div className="flex gap-1 h-3">
        {segments.map((_, i) => (
          <div key={i} className={`flex-1 rounded-sm transition-all duration-700 ${getColor(i)}`} />
        ))}
      </div>
    </div>
  );
};

