  const [results, setResults] = useState<AnalysisResult[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const leaderboard: LeaderboardEntry[] = useMemo(() => {
    const participants = Array.from(new Set(results.map(r => r.name)));
    return participants.map(name => ({
      id: Math.random().toString(36).substr(2, 9),
      username: name,
      points: results.filter(r => r.name === name).reduce((acc, curr) => acc + curr.score * 10, 0),
      avatar: getAvatarUrl(name)
    })).sort((a, b) => b.points - a.points).slice(0, 5);
  }, [results]);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    setIsAnalyzing(true);
    const filesArray = Array.from(files);

    try {
      // Process files sequentially to maintain order and avoid potential rate limits
      for (const file of filesArray) {
        const resizedBase64: string = await fastResize(file);
        const mimeType: string = file.type;
        const response = await analyzeImage(resizedBase64, mimeType);

        const newResult: AnalysisResult = {
          id: Math.random().toString(36).substr(2, 9),
          imageUrl: resizedBase64,
          name: extractParticipant(file.name),
          score: response.score,
          isAiGenerated: response.isAiGenerated,
          confidence: response.confidence,
          reasoning: response.reasoning,
          technicalDetails: response.technicalDetails,
          timestamp: Date.now(),
          status: 'success'
        };

        setResults(prev => [newResult, ...prev]);
      }
    } catch (error: any) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      console.error("Analysis failed:", errorMessage);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const deleteResult = (id: string) => {
    setResults(prev => prev.filter(r => r.id !== id));
  };

  const rankedResults = useMemo(() => {
    return [...results].sort((a, b) => b.score - a.score);
  }, [results]);

  return (
    <div className="min-h-screen bg-[#0a0514] text-white font-sans selection:bg-purple-500/30 overflow-x-hidden pb-40">
      <Header />

      <main className="max-w-7xl mx-auto px-6">
        {/* Upload Section */}
        <section className="mb-32 flex flex-col items-center">
          <div className="w-full max-w-3xl relative">
            {/* Animated Glow Backdrop */}
            <div className="absolute -inset-4 bg-gradient-to-r from-purple-600/20 via-indigo-600/20 to-purple-600/20 blur-3xl opacity-50 rounded-[4rem]"></div>

            <label className={`
              flex flex-col items-center justify-center w-full h-96 
