const getAvatarUrl = (username: string): string => {
  const seed = encodeURIComponent(username);
  return `https://api.dicebear.com/9.x/adventurer/svg?seed=${seed}&backgroundColor=0a0514&flip=true`;
};

const extractParticipant = (filename: string): string => {
  const nameWithoutExt = filename.replace(/\.[^/.]+$/, "");
  const parts = nameWithoutExt.split(/[-_ ]/);
  if (parts.length >= 2) {
    return parts.slice(0, 2).map(p => p.charAt(0).toUpperCase() + p.slice(1)).join(" ");
  }
  return parts[0].charAt(0).toUpperCase() + parts[0].slice(1);
};

const fastResize = (file: File, maxWidth = 1024): Promise<string> => {
  return new Promise((resolve) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement('canvas');
        let width = img.width;
        let height = img.height;

        if (width > maxWidth) {
          height *= maxWidth / width;
          width = maxWidth;
        }

        canvas.width = width;
        canvas.height = height;
        const ctx = canvas.getContext('2d');
        ctx?.drawImage(img, 0, 0, width, height);
        resolve(canvas.toDataURL('image/jpeg', 0.8));
      };
      img.src = e.target?.result as string;
    };
    reader.readAsDataURL(file);
  });
};

const downloadImage = (url: string, filename: string) => {
  const link = document.createElement('a');
  link.href = url;
  link.download = `PYTHENIAN-ELITE-ARCHIVE-${filename.replace(/\s+/g, '-').toUpperCase()}`;
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};

