              <div className="relative z-10 flex flex-col items-center gap-8">
                <div className={`p-8 rounded-[2.5rem] transition-all duration-700 shadow-2xl ${isAnalyzing ? 'bg-purple-600 text-white scale-125 rotate-180' : 'bg-purple-500/20 text-purple-400 group-hover:bg-purple-500 group-hover:text-white group-hover:scale-110'}`}>
