${winners.map((w, i) => `║ RANK #${i+1}: ${w.name.padEnd(30)} SCORE: ${String(w.score).padEnd(2)}/10 ║`).join('\n')}
╚══════════════════════════════════════════════════════════╝
  `;
  const blob = new Blob([content], { type: 'text/plain' });
