// --- Forensic Utilities ---

const extractParticipant = (filename: string): string => {
  const nameWithoutExt = filename.replace(/\.[^/.]+$/, "");
  const parts = nameWithoutExt.split(/[-_ ]/);
  if (parts.length >= 2) {
    return parts.slice(0, 2).map(p => p.charAt(0).toUpperCase() + p.slice(1)).join(" ");
  }
  return parts[0].charAt(0).toUpperCase() + parts[0].slice(1);
};

const fastResize = (file: File, maxWidth = 1024): Promise<string> => {
  return new Promise((resolve) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement('canvas');
        let width = img.width;
        let height = img.height;
        if (width > maxWidth) {
          height *= maxWidth / width;
          width = maxWidth;
        }
        canvas.width = width;
        canvas.height = height;
        const ctx = canvas.getContext('2d');
        ctx?.drawImage(img, 0, 0, width, height);
        resolve(canvas.toDataURL('image/jpeg', 0.8));
      };
      img.src = e.target?.result as string;
    };
    reader.readAsDataURL(file);
  });
};

const downloadImage = (url: string, filename: string) => {
  const link = document.createElement('a');
  link.href = url;
  link.download = `PYTHENIAN-ELITE-ARCHIVE-${filename.replace(/\s+/g, '-').toUpperCase()}`;
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};

// Generates a high-fidelity visual card for the champion
const generateChampionCard = async (result: AnalysisResult) => {
  const canvas = document.createElement('canvas');
  const ctx = canvas.getContext('2d');
  if (!ctx) return;

  const width = 1200;
  const height = 1600;
  canvas.width = width;
  canvas.height = height;

  // 1. Background
  const gradient = ctx.createLinearGradient(0, 0, 0, height);
  gradient.addColorStop(0, '#1c1131');
  gradient.addColorStop(1, '#05020a');
  ctx.fillStyle = gradient;
  ctx.fillRect(0, 0, width, height);

  // 2. Load and draw champion image
  const img = new Image();
  img.crossOrigin = "anonymous";
  await new Promise((resolve) => {
    img.onload = resolve;
    img.src = result.imageUrl;
  });

  // Calculate scaling for the image (centered square)
  const imgSize = 800;
  const imgX = (width - imgSize) / 2;
  const imgY = 300;

  // Draw glowing frame back
  ctx.shadowBlur = 50;
  ctx.shadowColor = '#fbbf24';
  ctx.strokeStyle = '#fbbf24';
  ctx.lineWidth = 15;
  ctx.strokeRect(imgX - 10, imgY - 10, imgSize + 20, imgSize + 20);
  ctx.shadowBlur = 0;

  ctx.drawImage(img, imgX, imgY, imgSize, imgSize);

  // 3. Texts
  ctx.fillStyle = '#ffffff';
  ctx.textAlign = 'center';

  // Title
  ctx.font = 'black 30px Orbitron, sans-serif';
  ctx.letterSpacing = '10px';
  ctx.fillStyle = '#fbbf24';
  ctx.fillText('OFFICIAL PYTHENIAN CHAMPION', width / 2, 180);

  // Name
  ctx.font = 'bold 80px Inter, sans-serif';
  ctx.fillStyle = '#ffffff';
  ctx.fillText(result.name.toUpperCase(), width / 2, 1220);

  // Score
  ctx.font = '900 120px JetBrains Mono, monospace';
  ctx.fillStyle = '#fbbf24';
  ctx.fillText(`${result.score}/10`, width / 2, 1380);

  ctx.font = 'bold 20px JetBrains Mono, monospace';
  ctx.fillStyle = 'rgba(255,255,255,0.3)';
  ctx.fillText(`NEURAL ID: ${result.id.toUpperCase()}`, width / 2, 1430);
  ctx.fillText(`BOUNTY CLAIMED: 50,000 PYTH POINTS`, width / 2, 1470);

  // 4. Branding
  ctx.font = '900 40px Orbitron, sans-serif';
  ctx.fillStyle = 'rgba(139, 92, 246, 0.5)';
  ctx.fillText('PYTHENIANS LABO', width / 2, 1550);

  // 5. Download
  const link = document.createElement('a');
  link.download = `CHAMPION-CARD-${result.name.toUpperCase()}.png`;
  link.href = canvas.toDataURL('image/png');
  link.click();
};

const archivePodiumReport = (winners: AnalysisResult[]) => {
  const date = new Date().toLocaleString();
  const content = `
╔══════════════════════════════════════════════════════════╗
║           PYTHENIANS LABO - ELITE PODIUM ARCHIVE         ║
╠══════════════════════════════════════════════════════════╣
║ TIMESTAMP: ${date.padEnd(46)} ║
╠══════════════════════════════════════════════════════════╣
${winners.map((w, i) => `║ RANK #${i+1}: ${w.name.padEnd(30)} SCORE: ${String(w.score).padEnd(2)}/10 ║`).join('\n')}
╚══════════════════════════════════════════════════════════╝
  `;
  const blob = new Blob([content], { type: 'text/plain' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.href = url;
  link.download = `PYTHENIAN-ELITE-PODIUM-${Date.now()}.txt`;
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};

