// Replicates the Podium Card UI on a Canvas for high-fidelity saving
const generateChampionCard = async (result: AnalysisResult) => {
  const canvas = document.createElement('canvas');
  const ctx = canvas.getContext('2d');
  if (!ctx) return;

  const width = 800;
  const height = 1100;
  canvas.width = width;
  canvas.height = height;

  // Helper for rounded rects
  const drawRoundedRect = (x: number, y: number, w: number, h: number, r: number) => {
    ctx.beginPath();
    ctx.moveTo(x + r, y);
    ctx.lineTo(x + w - r, y);
    ctx.quadraticCurveTo(x + w, y, x + w, y + r);
    ctx.lineTo(x + w, y + h - r);
    ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
    ctx.lineTo(x + r, y + h);
    ctx.quadraticCurveTo(x, y + h, x, y + h - r);
    ctx.lineTo(x, y + r);
    ctx.quadraticCurveTo(x, y, x + r, y);
    ctx.closePath();
  };

  // 1. Transparent Background or dark fill
  ctx.fillStyle = '#0a0514';
  ctx.fillRect(0, 0, width, height);

  // 2. Load and draw champion image in its frame
  const img = new Image();
  img.crossOrigin = "anonymous";
  await new Promise((resolve) => {
    img.onload = resolve;
    img.src = result.imageUrl;
  });

  const imgSize = 400;
  const imgX = (width - imgSize) / 2;
  const imgY = 120;

  // Draw Frame (Yellow Border)
  ctx.strokeStyle = '#fbbf2466'; // yellow-400/40
  ctx.lineWidth = 4;
  drawRoundedRect(imgX - 4, imgY - 4, imgSize + 8, imgSize + 8, 40);
  ctx.stroke();

  // Clip Image
  ctx.save();
  drawRoundedRect(imgX, imgY, imgSize, imgSize, 36);
  ctx.clip();
  ctx.drawImage(img, imgX, imgY, imgSize, imgSize);
  ctx.restore();

  // 3. Draw Podium Base (The Step)
  const stepY = 560;
  const stepH = 480;
  const stepW = 600;
  const stepX = (width - stepW) / 2;

  // Gradient for step
  const stepGrad = ctx.createLinearGradient(0, stepY, 0, stepY + stepH);
  stepGrad.addColorStop(0, 'rgba(251, 191, 36, 0.2)'); // yellow-400/20
  stepGrad.addColorStop(1, 'rgba(202, 138, 4, 0.1)'); // yellow-600/10

  ctx.fillStyle = stepGrad;
  ctx.strokeStyle = '#fbbf2466'; // border-yellow-400/40
  ctx.lineWidth = 4;

  // Custom path for step (rounded top)
  ctx.beginPath();
  const r = 56; // 3.5rem equivalent
  ctx.moveTo(stepX + r, stepY);
  ctx.lineTo(stepX + stepW - r, stepY);
  ctx.quadraticCurveTo(stepX + stepW, stepY, stepX + stepW, stepY + r);
  ctx.lineTo(stepX + stepW, stepY + stepH);
  ctx.lineTo(stepX, stepY + stepH);
  ctx.lineTo(stepX, stepY + r);
  ctx.quadraticCurveTo(stepX, stepY, stepX + r, stepY);
  ctx.closePath();
  ctx.fill();
  ctx.stroke();

  // 4. Texts in Step
  ctx.textAlign = 'center';

  // Rank Number (#1)
  ctx.font = '900 120px Inter, sans-serif';
  ctx.fillStyle = '#fbbf24';
  ctx.fillText('#1', width / 2, stepY + 140);

  // Name
  ctx.font = 'bold 54px Inter, sans-serif';
  ctx.fillStyle = '#ffffff';
  ctx.fillText(result.name, width / 2, stepY + 220);

  // Grade
  ctx.font = '900 24px JetBrains Mono, monospace';
  ctx.fillStyle = 'rgba(168, 85, 247, 0.6)'; // purple-400/60
  ctx.fillText(`${result.score}/10 GRADE`, width / 2, stepY + 270);

  // Reward
  ctx.font = '700 20px JetBrains Mono, monospace';
  ctx.fillStyle = 'rgba(255, 255, 255, 0.3)';
  ctx.fillText('50,000 PYTH POINTS', width / 2, stepY + 310);

  // 5. Badges
  // Label "CHAMPION" Badge
  const badgeW = 140;
  const badgeH = 40;
  const badgeX = (width - badgeW) / 2;
  const badgeY = 510;
  ctx.fillStyle = '#000000';
  ctx.strokeStyle = '#fbbf2466';
  ctx.lineWidth = 2;
  drawRoundedRect(badgeX, badgeY, badgeW, badgeH, 12);
  ctx.fill();
  ctx.stroke();

  ctx.font = '900 16px Inter, sans-serif';
  ctx.fillStyle = '#fbbf24';
  ctx.letterSpacing = '2px';
  ctx.fillText('CHAMPION', width / 2, badgeY + 26);
  ctx.letterSpacing = '0px';

  // 6. Branding / Watermark
  ctx.font = '900 24px Orbitron, sans-serif';
  ctx.fillStyle = 'rgba(139, 92, 246, 0.2)';
  ctx.fillText('PYTHENIANS LABO - NEURAL ARCHIVE', width / 2, height - 30);

  // Final Save
  const link = document.createElement('a');
  link.download = `PYTHENIAN-CHAMPION-${result.name.toUpperCase()}.png`;
  link.href = canvas.toDataURL('image/png');
  link.click();
};

