};

// Replicates the FULL Podium UI on a Canvas for high-fidelity saving of all winners
const generateFullPodiumImage = async (results: AnalysisResult[]) => {
  const canvas = document.createElement('canvas');
  const ctx = canvas.getContext('2d');
  if (!ctx || results.length === 0) return;

  const width = 2400; // Wider for 3 participants
  const height = 1400;
  canvas.width = width;
  canvas.height = height;

  const drawRoundedRect = (x: number, y: number, w: number, h: number, r: number) => {
    ctx.beginPath();
    ctx.moveTo(x + r, y);
    ctx.lineTo(x + w - r, y);
    ctx.quadraticCurveTo(x + w, y, x + w, y + r);
    ctx.lineTo(x + w, y + h - r);
    ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
    ctx.lineTo(x + r, y + h);
    ctx.quadraticCurveTo(x, y + h, x, y + h - r);
    ctx.lineTo(x, y + r);
    ctx.quadraticCurveTo(x, y, x + r, y);
    ctx.closePath();
  };

  // 1. Dark Background
  ctx.fillStyle = '#0a0514';
  ctx.fillRect(0, 0, width, height);

  // Background branding
  ctx.textAlign = 'center';
  ctx.font = '900 60px Orbitron, sans-serif';
  ctx.fillStyle = 'rgba(139, 92, 246, 0.1)';
  ctx.fillText('PYTHENIANS LABO - NEURAL ELITE ARCHIVE', width / 2, 120);

  // Config for the 3 positions
  const cardConfigs = [
    { rank: 2, x: 200, stepH: 500, color: '#94a3b8', grad: ['rgba(148,163,184,0.15)', 'rgba(100,116,139,0.05)'], reward: '30,000 PYTH PTS', label: 'CHALLENGER' },
    { rank: 1, x: 850, stepH: 650, color: '#fbbf24', grad: ['rgba(251,191,36,0.25)', 'rgba(202,138,4,0.1)'], reward: '50,000 PYTH PTS', label: 'CHAMPION' },
    { rank: 3, x: 1500, stepH: 400, color: '#b45309', grad: ['rgba(180,83,9,0.15)', 'rgba(120,53,15,0.05)'], reward: '20,000 PYTH PTS', label: 'ELITE' }
  ];

  // Map results to their ranks (Rank 1 = results[0], Rank 2 = results[1], Rank 3 = results[2])
  const rankMap: Record<number, AnalysisResult | null> = {
    1: results[0] || null,
    2: results[1] || null,
    3: results[2] || null,
  };

  // Draw each position
  for (const config of cardConfigs) {
    const result = rankMap[config.rank];
    if (!result) continue;

    // Load Image
    const img = new Image();
    img.crossOrigin = "anonymous";
    await new Promise((resolve) => {
      img.onload = resolve;
      img.src = result.imageUrl;
    });

    const cardW = 700;
    const imgSize = 350;
    const imgX = config.x + (cardW - imgSize) / 2;
    const imgY = config.rank === 1 ? 250 : 350;
    const stepTop = imgY + imgSize + 50;

    // A. Image Frame
    ctx.strokeStyle = config.color + '66';
    ctx.lineWidth = 6;
    drawRoundedRect(imgX - 6, imgY - 6, imgSize + 12, imgSize + 12, 45);
    ctx.stroke();

    ctx.save();
    drawRoundedRect(imgX, imgY, imgSize, imgSize, 40);
    ctx.clip();
    ctx.drawImage(img, imgX, imgY, imgSize, imgSize);
    ctx.restore();

    // B. Label Badge
    const bW = 180;
    const bH = 50;
    const bX = config.x + (cardW - bW) / 2;
    const bY = stepTop - 25;
    ctx.fillStyle = '#000000';
    ctx.strokeStyle = config.color + '66';
    ctx.lineWidth = 2;
    drawRoundedRect(bX, bY, bW, bH, 15);
    ctx.fill();
    ctx.stroke();

    ctx.font = '900 20px Inter, sans-serif';
    ctx.fillStyle = config.color;
    ctx.letterSpacing = '2px';
    ctx.fillText(config.label, config.x + cardW / 2, bY + 32);
    ctx.letterSpacing = '0px';

    // C. Step/Podium
    const stepGrad = ctx.createLinearGradient(0, stepTop, 0, height - 100);
    stepGrad.addColorStop(0, config.grad[0]);
    stepGrad.addColorStop(1, config.grad[1]);

    ctx.fillStyle = stepGrad;
    ctx.strokeStyle = config.color + '44';
    ctx.lineWidth = 4;

    const r = 80;
    ctx.beginPath();
    ctx.moveTo(config.x + r, stepTop);
    ctx.lineTo(config.x + cardW - r, stepTop);
    ctx.quadraticCurveTo(config.x + cardW, stepTop, config.x + cardW, stepTop + r);
    ctx.lineTo(config.x + cardW, height - 100);
    ctx.lineTo(config.x, height - 100);
    ctx.lineTo(config.x, stepTop + r);
    ctx.quadraticCurveTo(config.x, stepTop, config.x + r, stepTop);
    ctx.closePath();
    ctx.fill();
    ctx.stroke();

    // D. Step Text
    ctx.textAlign = 'center';

    // Rank
    ctx.font = '900 160px Inter, sans-serif';
    ctx.fillStyle = config.color;
    ctx.fillText(`#${config.rank}`, config.x + cardW / 2, stepTop + 200);

    // Name
    ctx.font = 'bold 64px Inter, sans-serif';
    ctx.fillStyle = '#ffffff';
    ctx.fillText(result.name, config.x + cardW / 2, stepTop + 300);

    // Grade
    ctx.font = '900 32px JetBrains Mono, monospace';
    ctx.fillStyle = 'rgba(168, 85, 247, 0.7)';
    ctx.fillText(`${result.score}/10 GRADE`, config.x + cardW / 2, stepTop + 370);

    // Reward
    ctx.font = '700 28px JetBrains Mono, monospace';
    ctx.fillStyle = 'rgba(255, 255, 255, 0.4)';
    ctx.fillText(config.reward, config.x + cardW / 2, stepTop + 430);
  }

  // 3. Branding footer
  ctx.font = '900 40px Orbitron, sans-serif';
  ctx.fillStyle = 'rgba(255,255,255,0.05)';
  ctx.fillText('VALIDATED BY PYTHENIAN FORENSIC NEURAL NETWORK', width / 2, height - 40);

  // Final Download
  const link = document.createElement('a');
  link.download = `PYTHENIAN-PODIUM-ARCHIVE-${Date.now()}.png`;
  link.href = canvas.toDataURL('image/png');
  link.click();
};

