// --- Forensic Utilities ---

const extractParticipant = (filename: string): string => {
  const nameWithoutExt = filename.replace(/\.[^/.]+$/, "");
  const parts = nameWithoutExt.split(/[-_ ]/);
  if (parts.length >= 2) {
    return parts.slice(0, 2).map(p => p.charAt(0).toUpperCase() + p.slice(1)).join(" ");
  }
  return parts[0].charAt(0).toUpperCase() + parts[0].slice(1);
};

const fastResize = (file: File, maxWidth = 1024): Promise<string> => {
  return new Promise((resolve) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement('canvas');
        let width = img.width;
        let height = img.height;
        if (width > maxWidth) {
          height *= maxWidth / width;
          width = maxWidth;
        }
        canvas.width = width;
        canvas.height = height;
        const ctx = canvas.getContext('2d');
        ctx?.drawImage(img, 0, 0, width, height);
        resolve(canvas.toDataURL('image/jpeg', 0.8));
      };
      img.src = e.target?.result as string;
    };
    reader.readAsDataURL(file);
  });
};

const downloadImage = (url: string, filename: string) => {
  const link = document.createElement('a');
  link.href = url;
  link.download = `PYTHENIAN-ELITE-ARCHIVE-${filename.replace(/\s+/g, '-').toUpperCase()}`;
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};

// Replicates the FULL Podium UI on a Canvas for high-fidelity saving of all winners
const generateFullPodiumImage = async (results: AnalysisResult[]) => {
  const canvas = document.createElement('canvas');
  const ctx = canvas.getContext('2d');
  if (!ctx || results.length === 0) return;

  // Use a standard 16:9 aspect ratio for the export
  const width = 1920;
  const height = 1080;
  canvas.width = width;
  canvas.height = height;

  const drawRoundedRect = (x: number, y: number, w: number, h: number, r: number) => {
    ctx.beginPath();
    ctx.moveTo(x + r, y);
    ctx.lineTo(x + w - r, y);
    ctx.quadraticCurveTo(x + w, y, x + w, y + r);
    ctx.lineTo(x + w, y + h - r);
    ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
    ctx.lineTo(x + r, y + h);
    ctx.quadraticCurveTo(x, y + h, x, y + h - r);
    ctx.lineTo(x, y + r);
    ctx.quadraticCurveTo(x, y, x + r, y);
    ctx.closePath();
  };

  // 1. Solid Dark Background
  ctx.fillStyle = '#0a0514';
  ctx.fillRect(0, 0, width, height);

  // 2. Background branding (Header)
  ctx.textAlign = 'center';
  ctx.font = '900 48px Orbitron, sans-serif';
  ctx.fillStyle = 'rgba(139, 92, 246, 0.15)';
  ctx.fillText('PYTHENIANS LABO - NEURAL ELITE ARCHIVE', width / 2, 80);

  // Config for the 3 positions to match the visual layout exactly
  const cardConfigs = [
    { rank: 2, x: 150, stepH: 420, color: '#94a3b8', grad: ['rgba(148,163,184,0.12)', 'rgba(71,85,105,0.06)'], reward: '30,000 PYTH PTS', label: 'CHALLENGER' },
    { rank: 1, x: 670, stepH: 540, color: '#fbbf24', grad: ['rgba(251,191,36,0.18)', 'rgba(202,138,4,0.08)'], reward: '50,000 PYTH PTS', label: 'CHAMPION' },
    { rank: 3, x: 1190, stepH: 340, color: '#b45309', grad: ['rgba(180,83,9,0.15)', 'rgba(120,53,15,0.05)'], reward: '20,000 PYTH PTS', label: 'ELITE' }
  ];

  const rankMap: Record<number, AnalysisResult | null> = {
    1: results[0] || null,
    2: results[1] || null,
    3: results[2] || null,
  };

  // Global Offset to center vertically
  const verticalOffset = 100;

  // Draw each position
  for (const config of cardConfigs) {
    const result = rankMap[config.rank];
    if (!result) continue;

    // Load Image
    const img = new Image();
    img.crossOrigin = "anonymous";
    await new Promise((resolve) => {
      img.onload = resolve;
      img.src = result.imageUrl;
    });

    const cardW = 580;
    const imgSize = 280;
    const imgX = config.x + (cardW - imgSize) / 2;
    const imgY = config.rank === 1 ? 160 + verticalOffset : 240 + verticalOffset;
    const stepTop = imgY + imgSize + 40;

    // A. Image Frame (Yellow/Slate/Bronze Border)
    ctx.strokeStyle = config.color + '44';
    ctx.lineWidth = 4;
    drawRoundedRect(imgX - 4, imgY - 4, imgSize + 8, imgSize + 8, 32);
    ctx.stroke();

    ctx.save();
    drawRoundedRect(imgX, imgY, imgSize, imgSize, 28);
    ctx.clip();
    ctx.drawImage(img, imgX, imgY, imgSize, imgSize);
    ctx.restore();

    // B. Label Badge
    const bW = 140;
    const bH = 34;
    const bX = config.x + (cardW - bW) / 2;
    const bY = stepTop - 17;
    ctx.fillStyle = '#000000';
    ctx.strokeStyle = config.color + '66';
    ctx.lineWidth = 1.5;
    drawRoundedRect(bX, bY, bW, bH, 10);
    ctx.fill();
    ctx.stroke();

    ctx.font = '900 14px Inter, sans-serif';
    ctx.fillStyle = config.color;
    ctx.letterSpacing = '1px';
    ctx.fillText(config.label, config.x + cardW / 2, bY + 22);
    ctx.letterSpacing = '0px';

    // C. Step/Podium
    const stepGrad = ctx.createLinearGradient(0, stepTop, 0, height - 100);
    stepGrad.addColorStop(0, config.grad[0]);
    stepGrad.addColorStop(1, config.grad[1]);

    ctx.fillStyle = stepGrad;
    ctx.strokeStyle = config.color + '33';
    ctx.lineWidth = 3;

    const r = 60;
    ctx.beginPath();
    ctx.moveTo(config.x + r, stepTop);
    ctx.lineTo(config.x + cardW - r, stepTop);
    ctx.quadraticCurveTo(config.x + cardW, stepTop, config.x + cardW, stepTop + r);
    ctx.lineTo(config.x + cardW, height - 120);
    ctx.lineTo(config.x, height - 120);
    ctx.lineTo(config.x, stepTop + r);
    ctx.quadraticCurveTo(config.x, stepTop, config.x + r, stepTop);
    ctx.closePath();
    ctx.fill();
    ctx.stroke();

    // D. Step Text
    ctx.textAlign = 'center';

    // Rank Number
    ctx.font = '900 120px Inter, sans-serif';
    ctx.fillStyle = config.color;
    ctx.fillText(`#${config.rank}`, config.x + cardW / 2, stepTop + 140);

    // Name
    ctx.font = 'bold 48px Inter, sans-serif';
    ctx.fillStyle = '#ffffff';
    ctx.fillText(result.name, config.x + cardW / 2, stepTop + 220);

    // Grade
    ctx.font = '900 24px JetBrains Mono, monospace';
    ctx.fillStyle = 'rgba(168, 85, 247, 0.7)';
    ctx.fillText(`${result.score}/10 GRADE`, config.x + cardW / 2, stepTop + 280);

    // Reward
    ctx.font = '700 20px JetBrains Mono, monospace';
    ctx.fillStyle = 'rgba(255, 255, 255, 0.35)';
    ctx.fillText(config.reward, config.x + cardW / 2, stepTop + 330);
  }

  // 3. Branding footer (Validated...)
  ctx.font = '900 32px Orbitron, sans-serif';
  ctx.fillStyle = 'rgba(255,255,255,0.08)';
  ctx.fillText('VALIDATED BY PYTHENIAN FORENSIC NEURAL NETWORK', width / 2, height - 40);

  // Final Download
  const link = document.createElement('a');
  link.download = `PYTHENIAN-PODIUM-ARCHIVE-${Date.now()}.png`;
  link.href = canvas.toDataURL('image/png');
  link.click();
};

const archivePodiumReport = (winners: AnalysisResult[]) => {
  const date = new Date().toLocaleString();
  const content = `
╔══════════════════════════════════════════════════════════╗
║           PYTHENIANS LABO - ELITE PODIUM ARCHIVE         ║
╠══════════════════════════════════════════════════════════╣
║ TIMESTAMP: ${date.padEnd(46)} ║
╠══════════════════════════════════════════════════════════╣
${winners.map((w, i) => `║ RANK #${i+1}: ${w.name.padEnd(30)} SCORE: ${String(w.score).padEnd(2)}/10 ║`).join('\n')}
╚══════════════════════════════════════════════════════════╝
  `;
  const blob = new Blob([content], { type: 'text/plain' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.href = url;
  link.download = `PYTHENIAN-ELITE-PODIUM-${Date.now()}.txt`;
