import { GoogleGenAI, Type } from "@google/genai";
import { GeminiResponse } from "../types";

export const analyzeImage = async (base64Image: string, mimeType: string): Promise<GeminiResponse> => {
  // Always use named parameter for apiKey and directly use process.env.API_KEY
  // Create a new instance right before making an API call as per guidelines
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-flash-preview';

  const systemInstruction = `
    You are a world-class forensic digital art analyst at "Pythos Eyes".
    Your task is to analyze the provided image and determine if it is "AI Slop" (generic, low-effort AI generation) or a high-quality "Human/Professional Design".

    Criteria for Low Score (AI Slop):
    - Nonsensical anatomical details (fingers, limbs).
    - Unnatural "AI lighting" or over-polished, plasticky skin.
    - Hallucinated text or gibberish characters.
    - Artifacts in complex patterns (checkerboards, lace).
    - Lack of artistic intent or soul.

    Criteria for High Score (10/10):
    - High technical execution (perfect perspective, consistent lighting).
    - Deliberate artistic choices.
    - Clean typography and logical design layout.
    - Complexity that suggests human software usage (layers, brushes, intentional noise).

    Rate from 1 to 10:
    - 1: Obvious, low-quality AI slop.
    - 10: Masterpiece human design/art.
  `;

  // Standardize base64 data extraction to ensure it's a string
  const base64Data = base64Image.includes(',') ? base64Image.split(',')[1] : base64Image;

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        {
          inlineData: {
            mimeType,
            data: base64Data,
          },
        },
        {
          text: "Analyze this image. Provide the result in JSON format."
        },
      ],
    },
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          score: { type: Type.NUMBER, description: "Rating from 1-10" },
          isAiGenerated: { type: Type.BOOLEAN, description: "Whether it was likely generated by AI" },
          confidence: { type: Type.NUMBER, description: "Confidence percentage 0-100" },
          reasoning: { type: Type.STRING, description: "Brief explanation of the rating" },
          technicalDetails: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "List of specific forensic details found (e.g., 'mangled fingers', 'consistent lighting')"
          },
        },
        required: ["score", "isAiGenerated", "confidence", "reasoning", "technicalDetails"],
      },
    },
  });

  // response.text is a property. Trimming whitespace as per guidelines.
  const jsonStr = response.text?.trim() || "{}";
  return JSON.parse(jsonStr) as GeminiResponse;
};

