import { GoogleGenAI, Type } from "@google/genai";
import { GeminiResponse } from "../types";

export const analyzeImage = async (base64Image: string, mimeType: string): Promise<GeminiResponse> => {
  // Always use named parameter for apiKey and directly use process.env.API_KEY
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-flash-preview';

  const systemInstruction = `
    You are the lead forensic curator at "Pythos Eyes", the world's most advanced neural laboratory for digital art authentication.
    Your mission is to execute a deep-layer scan to differentiate between "AI Slop" (synthetic, generic, pattern-based generation) and "Real Art" (intentional human creativity, professional design, and soulful expression).

    DETECTION PARAMETERS FOR REAL ART (High Score 8.5 - 10.0):
    - MEDIA AUTHENTICITY: Look for specific physical or digital medium indicators—pencil grit, paper tooth, intentional brush jitter, ink feathering, or varying line weights that show manual pressure.
    - COMPOSITIONAL INTENT: Deep understanding of the Rule of Thirds, Golden Ratio, or deliberate subversion of these rules for narrative effect.
    - COLOR THEORY: Professional usage of analogous, complementary, or triadic color schemes that evoke specific moods, rather than the generic "rainbow vibrant" look of AI.
    - SOUL & NARRATIVE: Does the piece tell a story? Is there a clear focal point? Are the details logical and purposeful?
    - TECHNICAL PRECISION: Clean typography, logical perspective, and lighting that obeys physics or is stylized with consistency.

    DETECTION PARAMETERS FOR AI SLOP (Low Score 1.0 - 5.0):
    - "THE GLOSS": A generic, airbrushed, or over-polished plasticky texture that lacks real-world grit.
    - NONSENSICAL COMPLEXITY: High detail that, upon inspection, is just gibberish (e.g., jewelry that doesn't connect, lace patterns that morph into skin, stairs that lead nowhere).
    - ANATOMICAL FAILURE: Merged fingers, impossible limb angles, or "floating" clothes/accessories.
    - LIGHTING HALLUCINATION: Shadows cast from multiple impossible directions or glowing edges that shouldn't exist.
    - BACKGROUND NOISE: Backgrounds that blur into a soup of unrecognizable shapes.

    CRITICAL SCORING RULES:
    1. Use high-precision decimal ratings from 1.0 to 10.0 (e.g., 8.9, 4.2).
    2. NEVER give the same score twice in one session. Every pixel counts.
    3. Look for the "human error" that makes a piece perfect (e.g., a slightly imperfect circle that shows a steady hand rather than a perfect vector).
    4. Provide technical forensic details in your analysis.
  `;

  const base64Data = base64Image.includes(',') ? base64Image.split(',')[1] : base64Image;

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        {
          inlineData: {
            mimeType,
            data: base64Data,
          },
        },
        {
          text: "Conduct a full forensic scan of this artifact. Evaluate for human artistry vs synthetic slop. Provide a precise decimal rating and JSON output."
        },
      ],
    },
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          score: { type: Type.NUMBER, description: "Precision rating from 1.0-10.0" },
          isAiGenerated: { type: Type.BOOLEAN, description: "True if detected as synthetic slop" },
          confidence: { type: Type.NUMBER, description: "Forensic confidence level 0-100" },
          reasoning: { type: Type.STRING, description: "Detailed artistic and forensic reasoning" },
          technicalDetails: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "Specific markers found (e.g., 'consistent oil paint impasto', 'synthetic luminosity artifacts')"
          },
        },
        required: ["score", "isAiGenerated", "confidence", "reasoning", "technicalDetails"],
      },
    },
  });

  const jsonStr = response.text?.trim() || "{}";
  return JSON.parse(jsonStr) as GeminiResponse;
};

