// Replicates the FULL Podium UI on a Canvas with a DARK PURPLE GRADIENT theme
const generateFullPodiumImage = async (results: AnalysisResult[], totalPool: number) => {
  const canvas = document.createElement('canvas');
  const ctx = canvas.getContext('2d');
  if (!ctx || results.length === 0) return;

  const width = 1920;
  const height = 1080;
  canvas.width = width;
  canvas.height = height;

  const drawRoundedRect = (x: number, y: number, w: number, h: number, r: number) => {
    ctx.beginPath();
    ctx.moveTo(x + r, y);
    ctx.lineTo(x + w - r, y);
    ctx.quadraticCurveTo(x + w, y, x + w, y + r);
    ctx.lineTo(x + w, y + h - r);
    ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
    ctx.lineTo(x + r, y + h);
    ctx.quadraticCurveTo(x, y + h, x, y + h - r);
    ctx.lineTo(x, y + r);
    ctx.quadraticCurveTo(x, y, x + r, y);
    ctx.closePath();
  };

  // 1. DARK PURPLE GRADIENT Background
  const bgGrad = ctx.createLinearGradient(0, 0, width, height);
  bgGrad.addColorStop(0, '#0a0514');
  bgGrad.addColorStop(1, '#1c1131');
  ctx.fillStyle = bgGrad;
  ctx.fillRect(0, 0, width, height);

  // 2. Header Branding
  ctx.textAlign = 'center';
  ctx.font = '900 48px Orbitron, sans-serif';
  ctx.fillStyle = '#ffffff'; 
  ctx.fillText('PYTHOS EYES - NEURAL ELITE ARCHIVE', width / 2, 80);

  // Pool distribution
  const prizes = {
    1: Math.floor(totalPool * 0.5),
    2: Math.floor(totalPool * 0.3),
    3: Math.floor(totalPool * 0.2),
  };

  // Config for the 3 positions - Swapped 2nd to ELITE and 3rd to CHALLENGER
  const cardConfigs = [
    { rank: 2, x: 150, stepH: 420, color: '#94a3b8', grad: ['rgba(148, 163, 184, 0.15)', 'rgba(71, 85, 105, 0.05)'], reward: `${formatPoints(prizes[2])} PYTH PTS`, label: 'ELITE' },
    { rank: 1, x: 670, stepH: 540, color: '#fbbf24', grad: ['rgba(251, 191, 36, 0.25)', 'rgba(180, 83, 9, 0.1)'], reward: `${formatPoints(prizes[1])} PYTH PTS`, label: 'CHAMPION' },
    { rank: 3, x: 1190, stepH: 340, color: '#b45309', grad: ['rgba(180, 83, 9, 0.18)', 'rgba(120, 53, 15, 0.08)'], reward: `${formatPoints(prizes[3])} PYTH PTS`, label: 'CHALLENGER' }
  ];

  const rankMap: Record<number, AnalysisResult | null> = {
    1: results[0] || null,
    2: results[1] || null,
    3: results[2] || null,
  };

  const verticalOffset = 100;

  for (const config of cardConfigs) {
    const result = rankMap[config.rank];
    if (!result) continue;

    const img = new Image();
    img.crossOrigin = "anonymous";
    await new Promise((resolve) => {
      img.onload = resolve;
      img.src = result.imageUrl;
    });

    const cardW = 580;
    const imgSize = 280;
    const imgX = config.x + (cardW - imgSize) / 2;
    const imgY = config.rank === 1 ? 160 + verticalOffset : 240 + verticalOffset;
    const stepTop = imgY + imgSize + 40;

    // A. Image Frame
    ctx.strokeStyle = config.color + '66';
    ctx.lineWidth = 6;
    drawRoundedRect(imgX - 6, imgY - 6, imgSize + 12, imgSize + 12, 36);
    ctx.stroke();

    ctx.save();
    drawRoundedRect(imgX, imgY, imgSize, imgSize, 32);
    ctx.clip();
    ctx.drawImage(img, imgX, imgY, imgSize, imgSize);
    ctx.restore();

    // B. Badge Label
    const bW = 160;
    const bH = 38;
    const bX = config.x + (cardW - bW) / 2;
    const bY = stepTop - 19;
    ctx.fillStyle = '#000000';
    ctx.strokeStyle = config.color + '99';
    ctx.lineWidth = 2;
    drawRoundedRect(bX, bY, bW, bH, 12);
    ctx.fill();
    ctx.stroke();

    ctx.font = '900 14px Inter, sans-serif';
    ctx.fillStyle = config.color;
    ctx.letterSpacing = '1px';
    ctx.fillText(config.label, config.x + cardW / 2, bY + 25);
    ctx.letterSpacing = '0px';

    // C. Podium Step
    const stepGrad = ctx.createLinearGradient(0, stepTop, 0, height - 100);
    stepGrad.addColorStop(0, config.grad[0]);
    stepGrad.addColorStop(1, config.grad[1]);

    ctx.fillStyle = stepGrad;
    ctx.strokeStyle = config.color + '44';
    ctx.lineWidth = 3;

    const r = 60;
    ctx.beginPath();
    ctx.moveTo(config.x + r, stepTop);
    ctx.lineTo(config.x + cardW - r, stepTop);
    ctx.quadraticCurveTo(config.x + cardW, stepTop, config.x + cardW, stepTop + r);
    ctx.lineTo(config.x + cardW, height - 120);
    ctx.lineTo(config.x, height - 120);
    ctx.lineTo(config.x, stepTop + r);
    ctx.quadraticCurveTo(config.x, stepTop, config.x + r, stepTop);
    ctx.closePath();
    ctx.fill();
    ctx.stroke();

    // D. Podium Text
    ctx.textAlign = 'center';
    ctx.font = '900 130px Inter, sans-serif';
    ctx.fillStyle = config.color;
    ctx.fillText(`#${config.rank}`, config.x + cardW / 2, stepTop + 140);

    ctx.font = 'bold 52px Inter, sans-serif';
    ctx.fillStyle = '#ffffff'; 
    ctx.fillText(result.name, config.x + cardW / 2, stepTop + 225);

    ctx.font = '900 24px JetBrains Mono, monospace';
    ctx.fillStyle = '#a78bfa'; 
    ctx.fillText(`${result.score.toFixed(1)}/10 GRADE`, config.x + cardW / 2, stepTop + 285);

    ctx.font = '700 20px JetBrains Mono, monospace';
    ctx.fillStyle = 'rgba(255, 255, 255, 0.4)';
    ctx.fillText(config.reward, config.x + cardW / 2, stepTop + 335);
  }

  // 3. Footer Watermark as requested: "Pythos Eyes AI Slop By Kirito"
  ctx.font = '900 32px Orbitron, sans-serif';
  ctx.fillStyle = 'rgba(255, 255, 255, 0.2)';
  ctx.fillText('Pythos Eyes AI Slop By Kirito', width / 2, height - 40);

  const link = document.createElement('a');
  link.download = `PYTHOS-EYES-PODIUM-${Date.now()}.png`;
  link.href = canvas.toDataURL('image/png');
  link.click();
};

