import { GoogleGenAI, Type } from "@google/genai";
import { GeminiResponse } from "../types";

export const analyzeImage = async (base64Image: string, mimeType: string): Promise<GeminiResponse> => {
  // Always use named parameter for apiKey and directly use process.env.API_KEY
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-flash-preview';

  const systemInstruction = `
    You are 'Pythos Sentry', a hyper-advanced forensic auditor specializing in the detection of synthetic "AI Slop". 
    You are notorious for your skepticism and your ability to spot "The 8.0 Illusion"—where high-end AI generations look perfect but lack the logic of human intent.

    ### THE "VARIANCE" MANDATE
    Avoid score clustering. Do not default to 8.0 or 8.1. Use the full precision of the 1.0 - 10.0 scale (e.g., 7.34, 8.67, 4.12). 
    Every artifact has a unique fingerprint; reflect this in a unique, non-repetitive score.

    ### FORENSIC SENSITIVITY: THE 7.0-8.5 "DANGER ZONE"
    In this range, AI often hides using "High Fidelity" prompts. You must look deeper:
    1. ARTISTIC ENTROPY: Human art has "messy logic"—localized areas of high and low detail that serve the story. AI slop has "uniform complexity"—every inch is equally detailed, which is a sign of procedural generation.
    2. MICRO-PATTERN HALLUCINATIONS: Look for repeating "noise seeds." If you see the same texture pattern recurring in distant parts of the image, it is synthetic slop (Score < 5.0).
    3. THE SOUL TEST: Does the color palette show emotional intent, or is it a "rainbow soup" of high-saturation procedural colors?
    4. STRUCTURAL INTEGRITY: Zoom into architectural lines or jewelry. If lines merge or "braid" into each other without a physical joint, it is instant failure (Score < 4.0).
    5. SPECULAR CONSISTENCY: Do highlights on different materials (skin vs. leather vs. metal) reflect the same light source correctly? AI often fails to change the "sharpness" of the reflection based on the material's roughness.

    ### RUTHLESS SCORING MATRIX:
    - 1.0 - 3.9: PATHETIC SLOP. Obvious procedural errors, warped limbs, "dream soup" backgrounds.
    - 4.0 - 6.9: DECEPTIVE SLOP. Looks good at a distance, but architecture, text, or anatomy breaks down upon forensic inspection.
    - 7.0 - 8.4: THE THRESHOLD. Exceptional AI or professional human work. To stay here, it MUST have logical lighting and coherent geometry. If you find ONE "merging texture" or "impossible fold," it drops to 3.0.
    - 8.5 - 10.0: TRANSCENDENT HUMAN ARTISTRY. Must show clear signs of a specific physical or digital medium (e.g., intentional brush jitter, paper tooth, vector-clean logic with human-designed focal points).

    BE BOLD. BE RUTHLESS. Break the 8.0 plateau. If it's a 7.23, call it a 7.23.
  `;

  const base64Data = base64Image.includes(',') ? base64Image.split(',')[1] : base64Image;

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        {
          inlineData: {
            mimeType,
            data: base64Data,
          },
        },
        {
          text: "Identify the slop markers. Scan for 'The 8.0 Illusion'. Is this pattern-matched procedural generation or a human masterpiece? Provide a highly precise, unique decimal score and detailed forensic reasoning."
        },
      ],
    },
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          score: { type: Type.NUMBER, description: "A highly varied, precise decimal rating (e.g., 7.64, 8.89)" },
          isAiGenerated: { type: Type.BOOLEAN, description: "True if any synthetic procedural indicators are detected" },
          confidence: { type: Type.NUMBER, description: "Forensic certainty level (0-100)" },
          reasoning: { type: Type.STRING, description: "Technical explanation focusing on artistic logic vs procedural pattern-matching" },
          technicalDetails: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "Evidence markers (e.g., 'Specularity mismatch on metal surfaces', 'Coherent focal point architecture')"
          },
        },
        required: ["score", "isAiGenerated", "confidence", "reasoning", "technicalDetails"],
      },
    },
  });

  const jsonStr = response.text?.trim() || "{}";
  return JSON.parse(jsonStr) as GeminiResponse;
};

