/**
 * NeuralGauge - A high-tech SVG-based score visualization component.
 * Features an animated arc, dynamic coloring, and forensic status markers.
 */
const NeuralGauge = ({ score }: { score: number }) => {
  const [animatedScore, setAnimatedScore] = useState(0);

  useEffect(() => {
    const timeout = setTimeout(() => setAnimatedScore(score), 100);
    return () => clearTimeout(timeout);
  }, [score]);

  // SVG dimensions & configuration
  const size = 200;
  const strokeWidth = 14;
  const center = size / 2;
  const radius = center - strokeWidth;
  const circumference = 2 * Math.PI * radius;

  // Angle of the semi-circle (from -180 to 0 degrees approx)
  const offset = circumference * (1 - (animatedScore / 10));

  const getStatus = () => {
    if (score >= 8.5) return { label: 'TRANSCENDENT', color: 'text-emerald-400', icon: <Crown className="w-4 h-4" /> };
    if (score >= 7.0) return { label: 'SKILLED HUMAN', color: 'text-indigo-400', icon: <ShieldCheck className="w-4 h-4" /> };
    if (score >= 4.0) return { label: 'DECEPTIVE SLOP', color: 'text-amber-400', icon: <AlertTriangle className="w-4 h-4" /> };
    return { label: 'CRITICAL SLOP', color: 'text-rose-500', icon: <Activity className="w-4 h-4" /> };
  };

  const getColor = () => {
    if (score >= 8.5) return '#10b981'; // Emerald
    if (score >= 7.0) return '#6366f1'; // Indigo
    if (score >= 4.0) return '#f59e0b'; // Amber
    return '#f43f5e'; // Rose
  };

  const status = getStatus();

  return (
    <div className="relative flex flex-col items-center group">
      <div className="relative w-full max-w-[200px] aspect-square">
        <svg 
          viewBox={`0 0 ${size} ${size}`} 
          className="transform -rotate-90 w-full h-full transition-all duration-1000 group-hover:scale-105"
        >
          {/* Background Track */}
          <circle
            cx={center}
            cy={center}
            r={radius}
            fill="none"
            stroke="rgba(255,255,255,0.03)"
            strokeWidth={strokeWidth}
            className="transition-all"
          />

          {/* Animated Progress Path */}
          <circle
            cx={center}
            cy={center}
            r={radius}
            fill="none"
            stroke={getColor()}
            strokeWidth={strokeWidth}
            strokeDasharray={circumference}
            strokeDashoffset={offset}
            strokeLinecap="round"
            style={{ 
              transition: 'stroke-dashoffset 1.5s cubic-bezier(0.34, 1.56, 0.64, 1)',
              filter: `drop-shadow(0 0 8px ${getColor()}44)`
            }}
          />

          {/* Forensic Ticks */}
          {Array.from({ length: 11 }).map((_, i) => {
            const angle = (i * 36);
            return (
              <line
                key={i}
                x1={center + (radius + 15) * Math.cos((angle * Math.PI) / 180)}
                y1={center + (radius + 15) * Math.sin((angle * Math.PI) / 180)}
                x2={center + (radius + 25) * Math.cos((angle * Math.PI) / 180)}
                y2={center + (radius + 25) * Math.sin((angle * Math.PI) / 180)}
                stroke={i <= animatedScore ? getColor() : "rgba(255,255,255,0.1)"}
                strokeWidth="2"
                className="transition-all duration-1000"
              />
            );
          })}
        </svg>

        {/* Center Readout */}
        <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
          <span className="text-[10px] font-black text-white/30 tracking-widest uppercase mb-1">SCORE</span>
          <div className="flex items-baseline gap-1">
            <span className="text-5xl font-black text-white tracking-tighter tabular-nums drop-shadow-2xl">
              {animatedScore.toFixed(1)}
            </span>
          </div>
          <div className={`mt-2 px-3 py-1 rounded-full border bg-black/40 backdrop-blur-md flex items-center gap-2 transition-all duration-500 border-white/10 ${status.color}`}>
             {status.icon}
             <span className="text-[9px] font-black uppercase tracking-tighter">{status.label}</span>
          </div>
        </div>
      </div>

      {/* Threshold Markers */}
      <div className="w-full mt-6 flex justify-between text-[8px] font-black font-mono text-white/20 uppercase tracking-widest px-2">
        <span>SLOP</span>
        <span>SUSPICIOUS</span>
        <span>ARTISTRY</span>
      </div>
    </div>
  );
};

